INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (169, '151a23ea19840a30', 'Assistant Land Surveyor (Ref: 70526)', 'Meinhardt (Hong Kong) Limited', 'land_surveying', 'Hong Kong', NULL, 'Meinhardt is one of the world’s few multidisciplinary engineering, infrastructure, geospatial and land survey services and project management non-listed consulting firms employing over 6000 professional staffs in over 60 offices worldwide.

With 1200 staff in Hong Kong and China, we provide a full range of technically feasible and cost effective solutions for buildings, civil infrastructure, rail, highways, aviation, geospatial, land survey services and environmental projects.

We are looking for high calibre candidates to fill the following positions:

Assistant Land Surveyor

(Ref: 70526)

Job Duties:

Assist Land Surveyors in developing the BIM model initiatives by reviewing PLIS/EMMS data workflows, establishing sustainable BIM maintenance processes, and defining standard templates to support continuous asset updates and smart infrastructure management.Assist Land Surveyors in aligning BIM data requirements with the as-built BIM models handed over from the CKR project team, standardizing attributes, and supporting the first implementation of BIM-based Asset Information Models (AIM) for lighting installations.Assist Land Surveyors in developing and implementing the AI-driven Lighting Defects Detection System, including collecting user requirements, coordinating with contractors for data collection and integration, preparing tender specifications, conducting system performance reviews, and preparing evaluation reports and;Assist Land Surveyors in supervising the Survey Team of Lighting Division in support of the Engineers’ work;Assist Land Surveyors in overseeing the monthly and ad-hoc audit survey in strengthening the quality control on the lamp post data submitted under the three MOM contracts;Provide daily support on various GIS and IT systems of Lighting Division and system revamping including Works Order Information System (WOIS) and Public Lighting Information System (PLIS);Perform any other duties as assigned by his/her supervisors and to share other workload in Lighting Division.Employment Terms:

5 days’ work, Mondays (except Public Holidays) 0900-1800 , Tuesdays – Fridays (except Public Holidays) 0900-1745, normally 44 hours per week (including lunch break);Work location: Meinhardt offices or government department.Requirements:

A qualification recognized by the Hong Kong Institute of Surveyors (HKIS) as satisfying the academic requirements for corporate membership in the Land Surveying Division;Completed a 2-year graduate training scheme recognized by the HKIS or equivalent;Have Level 2 or above in Chinese Language and English Language in the HKDSE or HKCEE or equivalent;Knowledge of and possession of experience in Geographic Information System (GIS) and application development will be advantageous;With communication, teamwork, and problem-solving abilities;Good command of spoken and written English, Chinese and Putonghua;Prefer immediately available.Please send full resume, expected salary and availability by 11 June 2026 noon with ', '', 'https://www.hkis.org.hk/jobs.html?id=1349', 'hkis', '8 Jun, 2026', '', 1, 'entry', '2026-07-02 04:04:07', '2026-07-02 04:04:07', 1, '<p>Meinhardt is one of the world’s few multidisciplinary engineering, infrastructure, geospatial and land survey services and project management non-listed consulting firms employing over 6000 professional staffs in over 60 offices worldwide.</p>
<p>With 1200 staff in Hong Kong and China, we provide a full range of technically feasible and cost effective solutions for buildings, civil infrastructure, rail, highways, aviation, geospatial, land survey services and environmental projects.</p>
<p>We are looking for high calibre candidates to fill the following positions:</p>
<p>Assistant Land Surveyor</p>
<p>(Ref: 70526)</p>
<h3 class="jd-section-header">Job Duties</h3>
<ul class="jd-list"><li>Assist Land Surveyors in developing the BIM model initiatives by reviewing PLIS/EMMS data workflows, establishing sustainable BIM maintenance processes, and defining standard templates to support continuous asset updates and smart infrastructure management.Assist Land Surveyors in aligning BIM data requirements with the as-built BIM models handed over from the CKR project team, standardizing attributes, and supporting the first implementation of BIM-based Asset Information Models (AIM) for lighting installations.Assist Land Surveyors in developing and implementing the AI-driven Lighting Defects Detection System, including collecting user requirements, coordinating with contractors for data collection and integration, preparing tender specifications, conducting system performance reviews, and preparing evaluation reports and;Assist Land Surveyors in supervising the Survey Team of Lighting Division in support of the Engineers’ work;Assist Land Surveyors in overseeing the monthly and ad-hoc audit survey in strengthening the quality control on the lamp post data submitted under the three MOM contracts;Provide daily support on various GIS and IT systems of Lighting Division and system revamping including Works Order Information System (WOIS) and Public Lighting Information System (PLIS);Perform any other duties as assigned by his/her supervisors and to share other workload in Lighting Division.Employment Terms:</li></ul>
<p>5 days’ work, Mondays (except Public Holidays) 0900-1800 , Tuesdays – Fridays (except Public Holidays) 0900-1745, normally 44 hours per week (including lunch break);Work location: Meinhardt offices or government department.Requirements:</p>
<p>A qualification recognized by the Hong Kong Institute of Surveyors (HKIS) as satisfying the academic requirements for corporate membership in the Land Surveying Division;Completed a 2-year graduate training scheme recognized by the HKIS or equivalent;Have Level 2 or above in Chinese Language and English Language in the HKDSE or HKCEE or equivalent;Knowledge of and possession of experience in Geographic Information System (GIS) and application development will be advantageous;With communication, teamwork, and problem-solving abilities;Good command of spoken and written English, Chinese and Putonghua;Prefer immediately available.Please send full resume, expected salary and availability by 11 June 2026 noon with</p>', 0);
INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (170, '45ad5512928be086', 'Architectural / Surveying Graduate', 'Hospital Authority', 'other', 'Hong Kong', NULL, 'Hospital Authority Development and Works Graduate Trainee Programme (REF. NO.: HO2605019)


Application deadline: 12 June 2026


Online apply via https://ha.taleo.net/careersection/ha\_ext\_cs/jobdetail.ftl?job=HO2605019&lang=en


Position:
Architectural / Surveying Graduate


Rank:
Executive Assistant I
Cluster/Department:
Development and Works Divisions, Hospital Authority (HA) Head Office
Pay: HK$24,191 per month


Key Responsibilities:
We are looking for high potential candidates with passion to work on capital works projects and develop their professional Architectural / Surveying career in the Development & Works Division of the Hospital Authority (HA).
Selected candidates will undergo two years of practical training arranged by the HA. Depending on project needs and job rotations, the programme covers various project stages—including inception, feasibility study, schematic proposal, design, contract documentation, and construction management. Training is conducted under the guidance of professional Architects or Building Surveyors, fulfilling the requirements of The Hong Kong Institute of Architects (HKIA) or The Hong Kong Institute of Surveyors (HKIS).


The key responsibilities may include but not be limited to:


Architectural Graduate
1.Assist in preparing building proposals, programmes, funds bidding and selection of works agents.
2.Assist in exercising close control on quality of works, site progress, project budget and expenditure.


3.Assist in overseeing compliance of statutory requirements with respect to building facilities, building engineering operation and maintenance services in project.


4.Assist in facilitating smooth interface between hospitals, government departments, contractors, professional consultants, and other stakeholders.


5.Assist in managing, monitoring and preparing performance report of professional consultants appointed for delivery of projects.


6.Assist in monitoring the preparation of contractor documentations, cost plan, project programme, estimates, cashflow and final account.


7.Perform any other duties as assigned by supervisors.


Surveying Graduate
1.Assist in preparing building proposals, programmes, funds bidding and selection of works agents.
2.Assist in planning and implementing minor works projects in hospitals.


3.Assist in overseeing compliance of statutory requirements with respect to building facilities, building engineering operation and maintenance services in project.


4.Assist in managing works agents through contract meetings, site inspections and audits.


5.Take part in the rolling inspection against hospital facilities and managing associated repair works.


6.Assist in managing consultants to conduct tendering exercises for HA term maintenance contracts.


7.Perform any other duties as assigned by supervisors.


Entry Requirements:
1.University Graduates with experience.
Preferable Attributes/Exposure:
1.A university degree in Surveying and have not yet registered with the re', '', 'https://www.hkis.org.hk/jobs.html?id=1348', 'hkis', '29 May, 2026', '', 1, 'graduate', '2026-07-02 04:04:07', '2026-07-02 04:04:07', 1, '<p>Hospital Authority Development and Works Graduate Trainee Programme (REF. NO.: HO2605019)</p>
<p>Application deadline: 12 June 2026</p>
<p>Online apply via https://ha.taleo.net/careersection/ha\_ext\_cs/jobdetail.ftl?job=HO2605019&amp;lang=en</p>
<p>Position: Architectural / Surveying Graduate</p>
<p>Rank: Executive Assistant I Cluster/Department: Development and Works Divisions, Hospital Authority (HA) Head Office Pay: HK$24,191 per month</p>
<h3 class="jd-section-header">Key Responsibilities</h3>
<p>We are looking for high potential candidates with passion to work on capital works projects and develop their professional Architectural / Surveying career in the Development &amp; Works Division of the Hospital Authority (HA). Selected candidates will undergo two years of practical training arranged by the HA. Depending on project needs and job rotations, the programme covers various project stages—including inception, feasibility study, schematic proposal, design, contract documentation, and construction management. Training is conducted under the guidance of professional Architects or Building Surveyors, fulfilling the requirements of The Hong Kong Institute of Architects (HKIA) or The Hong Kong Institute of Surveyors (HKIS).</p>
<p>The key responsibilities may include but not be limited to:</p>
<p>Architectural Graduate 1.Assist in preparing building proposals, programmes, funds bidding and selection of works agents. 2.Assist in exercising close control on quality of works, site progress, project budget and expenditure.</p>
<p>3.Assist in overseeing compliance of statutory requirements with respect to building facilities, building engineering operation and maintenance services in project.</p>
<p>4.Assist in facilitating smooth interface between hospitals, government departments, contractors, professional consultants, and other stakeholders.</p>
<p>5.Assist in managing, monitoring and preparing performance report of professional consultants appointed for delivery of projects.</p>
<p>6.Assist in monitoring the preparation of contractor documentations, cost plan, project programme, estimates, cashflow and final account.</p>
<p>7.Perform any other duties as assigned by supervisors.</p>
<p>Surveying Graduate 1.Assist in preparing building proposals, programmes, funds bidding and selection of works agents. 2.Assist in planning and implementing minor works projects in hospitals.</p>
<p>3.Assist in overseeing compliance of statutory requirements with respect to building facilities, building engineering operation and maintenance services in project.</p>
<p>4.Assist in managing works agents through contract meetings, site inspections and audits.</p>
<p>5.Take part in the rolling inspection against hospital facilities and managing associated repair works.</p>
<p>6.Assist in managing consultants to conduct tendering exercises for HA term maintenance contracts.</p>
<p>7.Perform any other duties as assigned by supervisors.</p>
<h3 class="jd-section-header">Entry Requirements</h3>
