INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (243, '32bee3ee8bc97313', '合約助理土地測量師', '民政事務總署', 'other', '香港', '', '部門: 民政事務總署

薪酬: 月薪港幣31,695元

學歷要求: 
專業資格

入職條件: 
(a) 具備獲香港測量師學會承認為符合該會土地測量組正式會員所需學歷要求的資格[註(1)]；
(b) 取得上述學歷資格後，在香港測量師學會不時就該會土地測量組發出的專業評核試規則及指引所載的相關範疇具備至少兩年專業訓練及工作經驗，或同等經驗[註(2)]；以及
(c) 符合語文能力要求，即在香港中學文憑考試或香港中學會考，中國語文科和英國語文科，考獲第2級或以上成績，或具備同等成績[註(3)]。

註: 
(1) 申請人如在二零二六年九月三十日或之前已成為香港測量師學會土地測量組的正式會員，或具備同等專業資格；及在取得專業資格後在土地測量方面具備一年或以上相關的工作經驗，將不會獲考慮聘用為合約助理土地測量師。獲取錄的申請人必須就上述有關資料作出聲明。
(2) 如申請人尚未具備入職條件(b)所述至少兩年相關範疇的專業訓練及工作經驗，但正接受相關專業訓練，並將於二零二六年九月三十日或之前取得所需兩年專業訓練和工作經驗也可申請；申請人如獲錄用，必須在二零二六年九月三十日或之前取得最少兩年專業訓練資格及工作經驗才獲聘任。
(3) 2007年前的香港中學會考中國語文科和英國語文科(課程乙) E級成績，在行政上會被視為等同2007年或之後香港中學會考中國語文科和英國語文科第2級成績。

職責: 
合約助理土地測量師主要負責：
(1) 進行各類土地測量工作(包括大地測量、土地界線測量、地形測量及攝影測量)，以及與地理信息系統／數碼攝影測量有關的工作；
(2) 督導測量工作隊伍；
(3) 監督所有測量及製備圖則的工作；
(4) 協助高級土地測量師／土地測量師處理辦公室的日常行政工作；以及
(5) 按照上司指示執行任何其他職務。

福利: 
(1)	獲聘者如圓滿履行合約，而期間表現理想及行為良好，可獲發約滿酬金。如獲發酬金，酬金數額連同政府按照《強制性公積金計劃條例》的規定為獲聘者向強制性公積金計劃所作的供款，相等於獲聘者在合約期內所得基本薪金總額的15%；以及
(2)	獲聘者可按照《僱傭條例》的規定享有休息日、法定假日（或代替假日）、年假、產假/ 侍產假和疾病津貼等福利（如適用）。

申請手續: 
(1) 申請人必須透過公務員事務局的G.F. 340網上申請系統 (https://www.csb.gov.hk) 作網上申請。
(2) 申請人須在截止申請日期或之前將詳列相關工作經驗的履歷和證明其(a) 學歷；及(b) 工作經驗的相關證明文件副本電郵至[via CTgoodjobs Apply Now]，並在電郵及各證明文件副本上註明申請的職位名稱及網上申請編號。
(3) 申請書如資料不全或以親身、郵寄、傳真或電郵方式遞交、或未能提供所需證明文件，概不受理。
(4) 申請人如獲邀參加面試，必須提供證明其(a) 學歷；及(b) 工作經驗的相關證明文件正本以供核實其資格。申請人如未能提供所需文件正本以供核實其資格，其申請將不獲考慮。
(5) 面試邀請書會通過電郵發出，申請人必須在申請表格上清楚填寫個人的電郵地址。如在截止申請日期後八個星期內未接獲邀參加面試，可視作落選。

聘用條款: 
(1) 應徵者如獲錄用，將會按非公務員合約條款受聘，合約期不多於12個月。
(2) 續約與否須視乎屆時部門的服務需求及受聘人的工作表現而定。
(3) 受聘人或需於戶外、不定時工作以及在星期六、星期日及公眾假期工作。', '', 'https://jobs.ctgoodjobs.hk/job/10167553/%E5%90%88%E7%B4%84%E5%8A%A9%E7%90%86%E5%9C%9F%E5%9C%B0%E6%B8%AC%E9%87%8F%E5%B8%AB?utm_campaign=google_jobs_apply&utm_source=google_jobs_apply&utm_medium=organic', 'google_jobs_CTgoodjobs', '6 days ago', '', 1, 'entry', '2026-07-05 00:11:37', '2026-07-05 00:11:37', 1, '<p>部門: 民政事務總署</p>
<p>薪酬: 月薪港幣31,695元</p>
<p>學歷要求: 專業資格</p>
<p>入職條件: (a) 具備獲香港測量師學會承認為符合該會土地測量組正式會員所需學歷要求的資格[註(1)]； (b) 取得上述學歷資格後，在香港測量師學會不時就該會土地測量組發出的專業評核試規則及指引所載的相關範疇具備至少兩年專業訓練及工作經驗，或同等經驗[註(2)]；以及 (c) 符合語文能力要求，即在香港中學文憑考試或香港中學會考，中國語文科和英國語文科，考獲第2級或以上成績，或具備同等成績[註(3)]。</p>
<p>註: (1) 申請人如在二零二六年九月三十日或之前已成為香港測量師學會土地測量組的正式會員，或具備同等專業資格；及在取得專業資格後在土地測量方面具備一年或以上相關的工作經驗，將不會獲考慮聘用為合約助理土地測量師。獲取錄的申請人必須就上述有關資料作出聲明。 (2) 如申請人尚未具備入職條件(b)所述至少兩年相關範疇的專業訓練及工作經驗，但正接受相關專業訓練，並將於二零二六年九月三十日或之前取得所需兩年專業訓練和工作經驗也可申請；申請人如獲錄用，必須在二零二六年九月三十日或之前取得最少兩年專業訓練資格及工作經驗才獲聘任。 (3) 2007年前的香港中學會考中國語文科和英國語文科(課程乙) E級成績，在行政上會被視為等同2007年或之後香港中學會考中國語文科和英國語文科第2級成績。</p>
<p>職責: 合約助理土地測量師主要負責： (1) 進行各類土地測量工作(包括大地測量、土地界線測量、地形測量及攝影測量)，以及與地理信息系統／數碼攝影測量有關的工作； (2) 督導測量工作隊伍； (3) 監督所有測量及製備圖則的工作； (4) 協助高級土地測量師／土地測量師處理辦公室的日常行政工作；以及 (5) 按照上司指示執行任何其他職務。</p>
<p>福利: (1)	獲聘者如圓滿履行合約，而期間表現理想及行為良好，可獲發約滿酬金。如獲發酬金，酬金數額連同政府按照《強制性公積金計劃條例》的規定為獲聘者向強制性公積金計劃所作的供款，相等於獲聘者在合約期內所得基本薪金總額的15%；以及 (2)	獲聘者可按照《僱傭條例》的規定享有休息日、法定假日（或代替假日）、年假、產假/ 侍產假和疾病津貼等福利（如適用）。</p>
<p>申請手續: (1) 申請人必須透過公務員事務局的G.F. 340網上申請系統 (https://www.csb.gov.hk) 作網上申請。 (2) 申請人須在截止申請日期或之前將詳列相關工作經驗的履歷和證明其(a) 學歷；及(b) 工作經驗的相關證明文件副本電郵至[via CTgoodjobs Apply Now]，並在電郵及各證明文件副本上註明申請的職位名稱及網上申請編號。 (3) 申請書如資料不全或以親身、郵寄、傳真或電郵方式遞交、或未能提供所需證明文件，概不受理。 (4) 申請人如獲邀參加面試，必須提供證明其(a) 學歷；及(b) 工作經驗的相關證明文件正本以供核實其資格。申請人如未能提供所需文件正本以供核實其資格，其申請將不獲考慮。 (5) 面試邀請書會通過電郵發出，申請人必須在申請表格上清楚填寫個人的電郵地址。如在截止申請日期後八個星期內未接獲邀參加面試，可視作落選。</p>
<p>聘用條款: (1) 應徵者如獲錄用，將會按非公務員合約條款受聘，合約期不多於12個月。 (2) 續約與否須視乎屆時部門的服務需求及受聘人的工作表現而定。 (3) 受聘人或需於戶外、不定時工作以及在星期六、星期日及公眾假期工作。</p>', 0);
