INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (251, '328e383cbfc7649c', 'Assistant Land Surveyor (Ref: 70526)', 'Meinhardt Consulting Engineers', 'land_surveying', 'Hong Kong', '', 'Meinhardt is one of the world’s few multidisciplinary engineering, infrastructure, geospatial and land survey services and project management non-listed consulting firms employing over 6000 professional staffs in over 60 offices worldwide.

With 1200 staff in Hong Kong and China, we provide a full range of technically feasible and cost effective solutions for buildings, civil infrastructure, rail, highways, aviation, geospatial, land survey services and environmental projects.

We are looking for high calibre candidates to fill the following positions:

Assistant Land Surveyor

(Ref: 70526)

Job Duties:

Assist Land Surveyors in developing the BIM model initiatives by reviewing PLIS/EMMS data workflows, establishing sustainable BIM maintenance processes, and defining standard templates to support continuous asset updates and smart infrastructure management.Assist Land Surveyors in aligning BIM data requirements with the as-built BIM models handed over from the CKR project team, standardizing attributes, and supporting the first implementation of BIM-based Asset Information Models (AIM) for lighting installations.Assist Land Surveyors in developing and implementing the AI-driven Lighting Defects Detection System, including collecting user requirements, coordinating with contractors for data collection and integration, preparing tender specifications, conducting system performance reviews, and preparing evaluation reports and;Assist Land Surveyors in supervising the Survey Team of Lighting Division in support of the Engineers’ work;Assist Land Surveyors in overseeing the monthly and ad-hoc audit survey in strengthening the quality control on the lamp post data submitted under the three MOM contracts;Provide daily support on various GIS and IT systems of Lighting Division and system revamping including Works Order Information System (WOIS) and Public Lighting Information System (PLIS);Perform any other duties as assigned by his/her supervisors and to share other worklo', '', 'https://www.openjobs.com.hk/en/hongkong/job/assistant-land-surveyor-ref-70526-j281138?utm_campaign=google_jobs_apply&utm_source=google_jobs_apply&utm_medium=organic', 'google_jobs_OpenJobs', '1 day ago', '', 1, 'entry', '2026-07-07 00:12:01', '2026-07-07 00:12:01', 1, '<p>Meinhardt is one of the world’s few multidisciplinary engineering, infrastructure, geospatial and land survey services and project management non-listed consulting firms employing over 6000 professional staffs in over 60 offices worldwide.</p>
<p>With 1200 staff in Hong Kong and China, we provide a full range of technically feasible and cost effective solutions for buildings, civil infrastructure, rail, highways, aviation, geospatial, land survey services and environmental projects.</p>
<p>We are looking for high calibre candidates to fill the following positions:</p>
<p>Assistant Land Surveyor</p>
<p>(Ref: 70526)</p>
<h3 class="jd-section-header">Job Duties</h3>
<ul class="jd-list"><li>Assist Land Surveyors in developing the BIM model initiatives by reviewing PLIS/EMMS data workflows, establishing sustainable BIM maintenance processes, and defining standard templates to support continuous asset updates and smart infrastructure management.Assist Land Surveyors in aligning BIM data requirements with the as-built BIM models handed over from the CKR project team, standardizing attributes, and supporting the first implementation of BIM-based Asset Information Models (AIM) for lighting installations.Assist Land Surveyors in developing and implementing the AI-driven Lighting Defects Detection System, including collecting user requirements, coordinating with contractors for data collection and integration, preparing tender specifications, conducting system performance reviews, and preparing evaluation reports and;Assist Land Surveyors in supervising the Survey Team of Lighting Division in support of the Engineers’ work;Assist Land Surveyors in overseeing the monthly and ad-hoc audit survey in strengthening the quality control on the lamp post data submitted under the three MOM contracts;Provide daily support on various GIS and IT systems of Lighting Division and system revamping including Works Order Information System (WOIS) and Public Lighting Information System (PLIS);Perform any other duties as assigned by his/her supervisors and to share other worklo</li></ul>', 0);
