INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (262, '104326e38bfe714f', 'Cost Consultant, Infrastructure', 'Turner & Townsend', 'quantity_surveying', 'Hong Kong', NULL, 'Company DescriptionTurner & Townsend is a global professional services company with over 22,000 people in more than 60 countries. Working with our clients across real estate, infrastructure, energy and natural resources, we transform together delivering outcomes that improve people’s lives. Working in partnership makes it possible to deliver the world’s most impactful projects and programmes as we turn challenge into opportunity and complexity into success. Our capabilities include programme, project, cost, asset and commercial management, controls and performance, procurement and supply chain, net zero and digital solutions. We are majority-owned by CBRE Group, Inc., the world’s largest commercial real estate services and investment firm, with our partners holding a significant minority interest. Turner & Townsend and CBRE work together to provide clients with the premier programme, project and cost management offering in markets around the world.Please visit our website: www.turnerandtownsend.comJob DescriptionRole OverviewAs a Cost Manager, you are expected to manage the core functions of cost management services for construction projects, ensuring cost control and quality objectives are met. You are expected to ensure that client objectives are met through the delivery of an effective cost management service and foster a collaborative and high-performing project environment.Key ResponsibilitiesProject support and coordinationPossesses in-depth knowledge of pre-contract and post-contract cost management services.Experienced in estimating, rate analysis, and cost planning, with the ability to develop and present final cost plans to clients.Estimating and cost planning to include producing and presenting the final cost plan.Tendering and procurement, including managing the pre-qualification stage, producing the tender list, putting the preliminaries together, tender analysis, producing the tender report and compiling the contractual documents.Dealing effectively with post contract cost variances and support in change control processes, where applicable referring major changes to reporting manager.Governance & ReportingProducing monthly post contract cost reports and supporting the presentation to the client.Provide inputs to Value Engineering exercises, where applicable.Interfacing with the client and other consultants, at all project stages.Identifying ways in which cost management procedures, templates and products can be improved and referring ideas to the appropriate line manager.Knowledge management – Ensuring that key information and learning generated from each commission is input into the Turner & Townsend internal database.Collaborate to deliver our best work – Work as an effective member of the cost management team, including where appropriate, taking effective responsibility for Assistant Cost Managers.QualificationsRequirementsBachelor’s degree in Cost Management, Quantity Surveying, Construction, Engineering, or a related field; Mas', '', 'https://hk.linkedin.com/jobs/view/cost-consultant-infrastructure-at-turner-townsend-4435442936?position=22&pageNum=0&refId=b3UbP5l7NtxGoxsfjw468w%3D%3D&trackingId=vrp%2Big0AWrilFK2BlGyP9A%3D%3D', 'linkedin', '2026-07-08', '', 1, 'entry', '2026-07-08 00:12:48', '2026-07-08 00:12:48', 1, '<h3 class="jd-section-header">Company Description</h3>
<ul class="jd-list"><li>Turner &amp; Townsend is a global professional services company with over 22,000 people in more than 60 countries. Working with our clients across real estate, infrastructure, energy and natural resources, we transform together delivering outcomes that improve people’s lives. Working in partnership makes it possible to deliver the world’s most impactful projects and programmes as we turn challenge into opportunity and complexity into success. Our capabilities include programme, project, cost, asset and commercial management, controls and performance, procurement and supply chain, net zero and digital solutions. We are majority-owned by CBRE Group, Inc., the world’s largest commercial real estate services and investment firm, with our partners holding a significant minority interest. Turner &amp; Townsend and CBRE work together to provide clients with the premier programme, project and cost management offering in markets around the world.Please visit our website: www.turnerandtownsend.comJob DescriptionRole OverviewAs a Cost Manager, you are expected to manage the core functions of cost management services for construction projects, ensuring cost control and quality objectives are met. You are expected to ensure that client objectives are met through the delivery of an effective cost management service and foster a collaborative and high-performing project environment.Key ResponsibilitiesProject support and coordinationPossesses in-depth knowledge of pre-contract and post-contract cost management services.Experienced in estimating, rate analysis, and cost planning, with the ability to develop and present final cost plans to clients.Estimating and cost planning to include producing and presenting the final cost plan.Tendering and procurement, including managing the pre-qualification stage, producing the tender list, putting the preliminaries together, tender analysis, producing the tender report and compiling the contractual documents.Dealing effectively with post contract cost variances and support in change control processes, where applicable referring major changes to reporting manager.Governance &amp; ReportingProducing monthly post contract cost reports and supporting the presentation to the client.Provide inputs to Value Engineering exercises, where applicable.Interfacing with the client and other consultants, at all project stages.Identifying ways in which cost management procedures, templates and products can be improved and referring ideas to the appropriate line manager.Knowledge management – Ensuring that key information and learning generated from each commission is input into the Turner &amp; Townsend internal database.Collaborate to deliver our best work – Work as an effective member of the cost management team, including where appropriate, taking effective responsibility for Assistant Cost Managers.QualificationsRequirementsBachelor’s degree in Cost Management, Quantity Surveying, Construction, Engineering, or a related field; Mas</li></ul>', 0);
INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (263, '5c9cc1d86e6c117d', 'AD - Cost Consultant', 'Mace', 'quantity_surveying', 'Hong Kong', NULL, 'Mace combines global delivery consultancy experience to unlock potential in every person or project and redefine the boundaries of ambition. Our values shape the way we consult and define the people we want to join us on our journey.

The project:

A large‑scale public infrastructure enhancement programme involving complex civil, structural and MEP works across multiple interconnected sites. The project encompassed significant station‑area upgrades, tunnel interface works, systems integration, and critical asset renewal to improve network capacity, safety performance and long‑term operational resilience within one of Hong Kong’s most heavily used transport corridors.

You’ll be responsible for:

Advise on procurement strategies and contract selection, ensuring robust governance and value-driven outcomes.Deliver cost planning and estimates, presenting clear and accountable final cost plans.Lead procurement processes from prequalification through contract preparation, building strong stakeholder relationships.Supervise contract documentation, warranties, and bonds to secure formal execution.Manage valuations, cost control, and reporting to support informed decisions.Drive continuous improvement through lessons learned, best practice application, and team leadership.You’ll need to have:

Degree-qualified in quantity surveying/cost management (or equivalent). MRICS/RICS membership or equivalent, progressing toward fellowship.Delivers service excellence through strong cost planning, commercial insight and risk awareness.Applies sound contract knowledge, measurement methods and digital tools to drive value.Builds trusted stakeholder relationships through clear communication, negotiation and collaboration.Provides analytical judgement to resolve commercial, contractual and procurement challenges effectively.Proven expertise in cost forecasting, earned value analysis, cost/commercial reporting and controls.Our values

Safety first - Going home safe and well: We champion a safe, diverse and inclusive working environment, understanding the importance of wellbeing in every team.

Client focus - Deliver on our promise: We own the quality of deliverables, strategic outcomes and build long term relationships with our clients.

Integrity - Always do the right thing: We influence positive outcomes within our industry, while always aligning with our compliance obligations.

Create opportunity - For our people to excel: We champion a continuous improvement culture throughout all activities, inspiring our people and teams to develop.

Mace is an inclusive employer and welcomes interest from a diverse range of candidates. Even if you feel you do not fulfil all the criteria, please apply as you may still be the best candidate for this role or another role within our organisation.

We are also open to discussing part time, flexible, and hybrid working options if suitable within the role.', '', 'https://hk.linkedin.com/jobs/view/ad-cost-consultant-at-mace-4431673370?position=23&pageNum=0&refId=b3UbP5l7NtxGoxsfjw468w%3D%3D&trackingId=8A%2FIX2jisXQIXikhaypxJw%3D%3D', 'linkedin', '2026-07-08', '', 1, 'entry', '2026-07-08 00:12:48', '2026-07-08 00:12:48', 1, '<p>Mace combines global delivery consultancy experience to unlock potential in every person or project and redefine the boundaries of ambition. Our values shape the way we consult and define the people we want to join us on our journey.</p>
<p>The project:</p>
<p>A large‑scale public infrastructure enhancement programme involving complex civil, structural and MEP works across multiple interconnected sites. The project encompassed significant station‑area upgrades, tunnel interface works, systems integration, and critical asset renewal to improve network capacity, safety performance and long‑term operational resilience within one of Hong Kong’s most heavily used transport corridors.</p>
<p>You’ll be responsible for:</p>
<p>Advise on procurement strategies and contract selection, ensuring robust governance and value-driven outcomes.Deliver cost planning and estimates, presenting clear and accountable final cost plans.Lead procurement processes from prequalification through contract preparation, building strong stakeholder relationships.Supervise contract documentation, warranties, and bonds to secure formal execution.Manage valuations, cost control, and reporting to support informed decisions.Drive continuous improvement through lessons learned, best practice application, and team leadership.You’ll need to have:</p>
<p>Degree-qualified in quantity surveying/cost management (or equivalent). MRICS/RICS membership or equivalent, progressing toward fellowship.Delivers service excellence through strong cost planning, commercial insight and risk awareness.Applies sound contract knowledge, measurement methods and digital tools to drive value.Builds trusted stakeholder relationships through clear communication, negotiation and collaboration.Provides analytical judgement to resolve commercial, contractual and procurement challenges effectively.Proven expertise in cost forecasting, earned value analysis, cost/commercial reporting and controls.Our values</p>
<p>Safety first - Going home safe and well: We champion a safe, diverse and inclusive working environment, understanding the importance of wellbeing in every team.</p>
<p>Client focus - Deliver on our promise: We own the quality of deliverables, strategic outcomes and build long term relationships with our clients.</p>
<p>Integrity - Always do the right thing: We influence positive outcomes within our industry, while always aligning with our compliance obligations.</p>
<p>Create opportunity - For our people to excel: We champion a continuous improvement culture throughout all activities, inspiring our people and teams to develop.</p>
<p>Mace is an inclusive employer and welcomes interest from a diverse range of candidates. Even if you feel you do not fulfil all the criteria, please apply as you may still be the best candidate for this role or another role within our organisation.</p>
<p>We are also open to discussing part time, flexible, and hybrid working options if suitable within the role.</p>', 0);
