INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (278, 'fc48f8b1c132beef', '工場助理（油漆／土地測量）', 'VOCATIONAL TRAINING COUNCIL', 'land_surveying', '香港', '', 'VIBRANT AND VITAL VTC

VTC is a vocational and professional education and training provider established in Hong Kong in 1982. With some 200,000 students across our 14 member institutions, this not only makes us VIBRANT but VITAL to the Hong Kong educational landscape. We provide a spectrum of opportunities through multiple pathways for graduates to determine their own destination, whether it is employment or further studies. If you believe that the provision of a valued choice for learners to acquire the values, skills and knowledge for lifelong learning and enhanced employability is a worthy mission, then consider joining us.

香港專業教育學院（摩理臣山）
 
部門 : 建造工程系
參考編號 : C/MH-CN/MEC2(PLS)/06/26-AP1

主要職責：
(a)    為建造工程的教學工場（例如 : 油漆、土地測量等）提供教學支援；
(b)    準備、安排、分發及盤點課堂實習所需的材料及工具；
(c)    安裝、維修、搬運及保養實習工場的工具及設備，並處理維修計劃及保存良好記錄；
(d)    負責保持工場環境及設施之安全和清潔；及
(e)    支援學系舉辦之活動和展覽及外勤工作支援。
      
入職條件：
(a)    (i)    完成相關認可訓練課程（包括學徒及技工訓練），並於取得有關學歷後具有最少兩年相關工作經驗；或
        (ii)    通過技能測試或相等水平測試，並具有最少兩年相關工作經驗；
(b)    能閱讀及書寫中文和簡單英語；及
(c)    懂基本電腦操作。
           
備註：
(1)    以上職位之職級為「二級機械工」。
(2)    申請人如具有在相關領域中豐富經驗和成就但缺乏所需的學術／專業資格，或者具有卓越的學術／專業資格但經驗較少也可以申請。
(3)    應徵者或需參加技能測試。
(4)    受聘者可能需要輪班工作，並於星期六、日及公眾假期當值。
(5)    為配合運作需要，受聘者日後可能會被調派至其他工作地點工作。
(6)    申請人如在過去一年內曾就該職位遞交申請表格，則無須重新遞交。

申請辦法：
填妥的申請表格 [VTC-1 (Rev. 11/2024)] 連同個人履歷，須電郵至[email redacted, apply via Company website]。
 
申請人應注意以下事項：
(1)    填妥的申請表（VTC-1）和個人履歷應合併為一個PDF 格式的文件，檔案容量應不超過10MB。
(2)    文件名稱應為“您的英文姓氏和名字”，例如“CHAN Siu-lam.pdf”。
(3)    郵件主旨請註明“申請工場助理（油漆/土地測量）(C/MH-CN/MEC2(PLS)/06/26-AP1)”。
(4)    其他證明文件的正本及複印本請按要求於稍後提交。
           
申請人之篩選將會即時進行直至有關職位空缺已被填補為止。
 
本局保留不填補上述職位的權利。
 
申請人的資料只會用於有關本局的人事招聘事宜。 在一般情況下，未獲取錄申請人的資料將於招聘工作完成十二個月後全部銷毀。', '', 'https://www.recruit.net/job/%E5%B7%A5%E5%A0%B4%E5%8A%A9%E7%90%86%EF%BC%88%E6%B2%B9%E6%BC%86%EF%BC%8F%E5%9C%9F%E5%9C%B0%E6%B8%AC%E9%87%8F%EF%BC%89-jobs/28C40D3BC6FF6AE0?utm_campaign=google_jobs_apply&utm_source=google_jobs_apply&utm_medium=organic', 'google_jobs_Recruit.net', '2 days ago', '', 1, 'entry', '2026-07-10 00:11:51', '2026-07-10 00:11:51', 1, '<h3 class="jd-section-header">VIBRANT AND VITAL VTC</h3>
<p>VTC is a vocational and professional education and training provider established in Hong Kong in 1982. With some 200,000 students across our 14 member institutions, this not only makes us VIBRANT but VITAL to the Hong Kong educational landscape. We provide a spectrum of opportunities through multiple pathways for graduates to determine their own destination, whether it is employment or further studies. If you believe that the provision of a valued choice for learners to acquire the values, skills and knowledge for lifelong learning and enhanced employability is a worthy mission, then consider joining us.</p>
<p>香港專業教育學院（摩理臣山）</p>
<p>部門 : 建造工程系</p>
<h3 class="jd-section-header">參考編號 : C/MH-CN/MEC2(PLS)/06/26-AP1</h3>
<p>主要職責： (a)    為建造工程的教學工場（例如 : 油漆、土地測量等）提供教學支援； (b)    準備、安排、分發及盤點課堂實習所需的材料及工具； (c)    安裝、維修、搬運及保養實習工場的工具及設備，並處理維修計劃及保存良好記錄； (d)    負責保持工場環境及設施之安全和清潔；及 (e)    支援學系舉辦之活動和展覽及外勤工作支援。</p>
<p>入職條件： (a)    (i)    完成相關認可訓練課程（包括學徒及技工訓練），並於取得有關學歷後具有最少兩年相關工作經驗；或 (ii)    通過技能測試或相等水平測試，並具有最少兩年相關工作經驗； (b)    能閱讀及書寫中文和簡單英語；及 (c)    懂基本電腦操作。</p>
<p>備註： (1)    以上職位之職級為「二級機械工」。 (2)    申請人如具有在相關領域中豐富經驗和成就但缺乏所需的學術／專業資格，或者具有卓越的學術／專業資格但經驗較少也可以申請。 (3)    應徵者或需參加技能測試。 (4)    受聘者可能需要輪班工作，並於星期六、日及公眾假期當值。 (5)    為配合運作需要，受聘者日後可能會被調派至其他工作地點工作。 (6)    申請人如在過去一年內曾就該職位遞交申請表格，則無須重新遞交。</p>
<p>申請辦法： 填妥的申請表格 [VTC-1 (Rev. 11/2024)] 連同個人履歷，須電郵至[email redacted, apply via Company website]。</p>
<p>申請人應注意以下事項： (1)    填妥的申請表（VTC-1）和個人履歷應合併為一個PDF 格式的文件，檔案容量應不超過10MB。 (2)    文件名稱應為“您的英文姓氏和名字”，例如“CHAN Siu-lam.pdf”。 (3)    郵件主旨請註明“申請工場助理（油漆/土地測量）(C/MH-CN/MEC2(PLS)/06/26-AP1)”。 (4)    其他證明文件的正本及複印本請按要求於稍後提交。</p>
<p>申請人之篩選將會即時進行直至有關職位空缺已被填補為止。</p>
<p>本局保留不填補上述職位的權利。</p>
<p>申請人的資料只會用於有關本局的人事招聘事宜。 在一般情況下，未獲取錄申請人的資料將於招聘工作完成十二個月後全部銷毀。</p>', 0);
