INSERT OR REPLACE INTO jobs (id, external_id, title, company, discipline, location, salary_range, description, requirements, url, source, posted_date, closing_date, fresh_grad_friendly, experience_level, created_at, updated_at, is_active, description_html, last_seen_scrape) VALUES (294, 'fbcb6b5a6545a727', 'Resident Land Surveyor / 駐地盤土地測量師 Ref. No : RLS/19482/TRA', 'AECOM', 'land_surveying', '香港', '', 'Highways Department
路政署


Contract No. HY/2025/13


合約編號HY/2025/13


Widening of Yuen Long Highway (Section between Lam Tei Quarry and Tong Yan San Tsuen Interchange)


元朗公路擴闊工程（藍地石礦場至唐人新村交匯處段）


AECOM Asia Company Limited has been commissioned by the Highways Department to undertake the supervision of the captioned Contract, including carriageway widening, modification of slip roads, associated geotechnical works, landscaping works, road and drainage, waterworks and noise barrier construction. The works are scheduled to commence in June 2026 and will take about 48 months to complete.


艾奕康有限公司現招聘下列駐地盤工程人員負責上述政府合約之建造工程，涉及擴闊行車道、改建相關連接路、其他相關工程，包括土力工程、環境美化工程、道路及渠務工程、水務工程及建造隔音屏障。工程預計於2026年6月展開，約需時48個月完成。


Candidates should have:
 Membership of the Hong Kong Institute of Surveyors in Land Surveying Division or equivalent.  申請人必須:​
 為香港測量師學會(土地測量組別)的正式會員或具備同等資格。  Applicants may also refer to the other requirement(s) of the above opening(s) stipulated in Appendix 7.4 of “Management Handbook for Direct Employment of Resident Site Staff by Consultants for Public Works Projects” from the webpage of Development Bureau. 申請人亦可參閱發展局網頁“關於顧問公司直接僱用駐地盤人員的管理手冊”附錄7.4所載的其他同等學歷和經驗。
