INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (76, 226, 1, 85.0, '["PolyU BSc (Hons) in Surveying \u2013 directly relevant QS degree and automatic HKIS graduate pathway eligibility.", "Green Card (Construction Industry Safety Card) held \u2013 mandatory for site work.", "Cantonese proficiency listed \u2013 essential for HK site communication.", "Strong software skills including AutoCAD, Revit, CostX, Navisworks, Bluebeam, and BIM certification.", "HKIS Student Member and RICS Student Member \u2013 demonstrates professional commitment."]', '["Missing Construction Workers Registration Card (\u5efa\u9020\u696d\u5de5\u4eba\u8a3b\u518a\u8b49) \u2013 required by job posting.", "Only 0.5 years of experience, while job requires 1 year.", "No HK driving license \u2013 may be needed for site travel.", "No specific HK project experience mentioned (e.g., residential, commercial, government)."]', '["Obtain Construction Workers Registration Card before applying \u2013 it is a hard requirement.", "Highlight any HK project exposure from internship (e.g., if worked on HK projects at RLB, specify them).", "Consider getting HK driving license (Class 1) to improve mobility for site visits.", "Emphasize Cantonese proficiency more prominently in CV summary.", "Add a brief note on HKIS APC awareness and intention to enroll."]', 'BSc (Hons) Surveying graduate from The Hong Kong Polytechnic University with 6 months of practical experience in quantity surveying through a summer internship at Rider Levett Bucknall (RLB) and a part-time research assistant role at PolyU. Proficient in Cantonese, English, and Mandarin. Holds a Green Card and is a HKIS Student Member, eligible for the HKIS APC pathway. Skilled in AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, and BIM coordination. Seeking an Assistant Surveyor position to apply technical and measurement skills on HK construction sites.', 'Dear Hiring Manager,

