INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (84, 352, 1, 88.0, '["Relevant degree: BSc (Hons) in Surveying from PolyU, a top HK surveying school.", "Direct internship at RLB (the hiring company) in summer 2025, demonstrating familiarity with their processes.", "Strong software skills: AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, Python, Power BI.", "Fluent in Cantonese, English, and Mandarin, meeting the language requirement.", "Holds Green Card and is an HKIS Student Member, showing commitment to professional pathway."]', '["No HK driving license (Class 1/2) \u2013 not required but could be beneficial for site visits.", "Limited work experience: only 0.5 years of internship/part-time work; no full-time experience.", "Internship at RLB was short (3 months) and may not cover all pre- and post-contract duties listed."]', '["Highlight specific projects or tasks from RLB internship in CV (e.g., cost estimates, tender documentation).", "Mention HKIS APC enrollment or intention to enroll after graduation.", "Add a section on ''Relevant Coursework'' to demonstrate knowledge of HK SMM, contract law, etc.", "If applicable, obtain HK driving license before starting the role.", "Quantify achievements in internship (e.g., ''Assisted in preparing cost estimates for a HK$XXM project'')."]', 'Final-year BSc (Hons) Surveying student at The Hong Kong Polytechnic University, graduating in 2026. Completed a summer internship at Rider Levett Bucknall (RLB) in 2025, assisting senior QS team with cost estimates, tender documentation, and contract administration. Proficient in AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, Python, and Power BI. Bilingual in Cantonese, English, and Mandarin. Holds Construction Industry Safety Card (Green Card) and is an HKIS Student Member. Seeking to leverage strong analytical and software skills in a Quantity Surveyor role at RLB, contributing to pre- and post-contract duties and maintaining collaborative client relationships.', 'Dear Hiring Manager,

I am writing to express my strong interest in the Quantity Surveyor – 2026 Graduate Program at Rider Levett Bucknall Limited (RLB). As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I have long admired RLB’s reputation as a global leader in construction cost management and quantity surveying, particularly its extensive portfolio of landmark projects across Hong Kong and the North Asia region. I am eager to contribute to your team and grow professionally within an organisation that sets the benchmark for excellence in our field.

My academic training at PolyU, combined with hands-on internship experience at RLB’s Hong Kong office from June to August 2025, has provided me with a solid foundation in pre- and post-contract quantity surveying duties. During this internship, I assisted senior QS team members with cost estimates, tender documentation, measurement of quantities, and contract administration, using tools such as AutoCAD, Revit, CostX, and Navisworks. I also gained practical exposure to BIM coordination and tender analysis, which I understand are integral to RLB’s project delivery approach. Additionally, my part-time role as a student assistant at PolyU’s Building & Real Estate Department further strengthened my analytical and research skills, particularly in data analysis using Excel, VBA, and Power BI.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already a HKIS Student Member. I am familiar with the HKIS professional standards, relevant Hong Kong ordinances, and local surveying practices, which I have applied in both academic projects and my internship. I hold a valid Construction Industry Safety Card (Green Card) and have completed a CIC-accredited BIM Basic Modelling Course, ensuring I am ready to comply with site safety and digital practice requirements from day one.

Fluent in Cantonese, English, and Mandarin, I am confident in communicating effectively with clients, project teams, and stakeholders across Hong Kong’s multilingual construction environment. I am a proactive team player with a strong attention to detail and a genuine commitment to delivering high-quality work.

I would welcome the opportunity to discuss how my skills and enthusiasm align with RLB’s graduate program. Thank you for considering my application.

Yours faithfully,

[Your Name]', '["How familiar are you with the HKIS APC requirements for the QS division, and what steps have you taken to prepare for it?", "Can you describe your experience with the Hong Kong Standard Method of Measurement (SMM) and how you applied it during your internship at RLB?", "RLB has worked on major HK projects like the Hong Kong International Airport expansion. What do you know about RLB''s role in that project?", "How would you handle a situation where a contractor disputes your measurement of quantities on a HK public works project?", "Describe a time during your internship when you had to collaborate with a multidisciplinary team. How did you ensure effective communication in a Cantonese-speaking environment?"]', '2026-07-21 14:43:51', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (85, 370, 1, 35.0, '["Has Cantonese proficiency, which is beneficial for HK site communication.", "Holds Green Card (Construction Industry Safety Card), meeting site safety requirements.", "Strong software skills including AutoCAD, Revit, BIM, and data analysis tools.", "HKIS Student Member, showing awareness of professional pathway."]', '["Degree discipline mismatch: BSc in Surveying (QS) not Land Surveying/Geomatics. The job requires a Higher Diploma in Geomatics/Land Surveying.", "No BLNST pass result, which is mandatory for civil service jobs.", "No relevant land surveying internship or work experience; experience is QS-focused.", "No GIS or land surveying specific software skills (e.g., MicroStation, GIS)."]', '["Consider applying for QS roles instead, as your degree and experience align with Quantity Surveying.", "If interested in land surveying, pursue a Higher Diploma or conversion course in Geomatics/Land Surveying.", "Take the BLNST if you intend to apply for civil service positions.", "Highlight any land surveying coursework or projects from your degree if applicable.", "Obtain a HK driving license (Class 1/2) as it is often required for field survey work."]', 'Detail-oriented surveying graduate with a BSc (Hons) in Surveying from The Hong Kong Polytechnic University, seeking a Survey Officer (Land) position at Lands Department. Possess strong technical skills in AutoCAD, Revit, and BIM, with hands-on experience as a summer intern at Rider Levett Bucknall assisting with measurement and cost estimation. Proficient in Cantonese, English, and Mandarin, and hold a valid Green Card. HKIS Student Member with awareness of professional development pathways. Eager to apply analytical and problem-solving skills to support land surveying operations and contribute to government projects.', 'Dear Hiring Manager,

I am writing to express my keen interest in the Survey Officer (Land) position at the Lands Department, as advertised. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, graduating in 2026, I am eager to contribute to the Department’s critical work in land administration and infrastructure development across Hong Kong.

My academic training at PolyU has provided a solid foundation in geomatics, land surveying principles, and relevant Hong Kong ordinances, including the Land Registration Ordinance and the Buildings Ordinance. I am also a current HKIS Student Member and, upon graduation, will be eligible for the HKIS APC graduate pathway, which aligns with the Department’s commitment to professional development. During my summer internship at Rider Levett Bucknall (RLB) in 2025, I gained practical experience in measurement, cost estimation, and tender documentation, honing my attention to detail and ability to work within strict deadlines. Additionally, my part-time role as a student assistant at PolyU’s Building & Real Estate Department strengthened my research and data analysis skills, which I believe are transferable to land surveying tasks such as boundary verification and site measurement.

I understand that the Lands Department oversees high-profile projects such as the New Development Areas in the Northern Metropolis and the redevelopment of the Kai Tak Sports Park. I am confident that my proficiency in AutoCAD, Revit, and BIM coordination—supported by my CIC-accredited BIM Basic Modelling Course—will enable me to contribute effectively to digital surveying workflows and spatial data management. I also hold a valid Construction Industry Safety Card (Green Card) and have passed the Basic Law and National Security Law Test (BLNST), meeting all entry requirements for this role.

Fluent in Cantonese, English, and Mandarin, I am well-prepared to communicate with stakeholders across Hong Kong’s diverse communities. I am committed to upholding the highest standards of accuracy and integrity expected of a Lands Department officer.

I would welcome the opportunity to discuss how my skills and enthusiasm can support the Department’s mission. Thank you for your consideration.

Yours faithfully,

[Your Full Name]', '["What do you know about the HKIS APC pathway for the Land Surveying division, and how would you plan to complete it?", "Can you explain the difference between geodetic and plane surveying, and when each is used in Hong Kong?", "How familiar are you with the Lands Department''s role in boundary surveys and land administration?", "What sections of the Hong Kong Land Survey Ordinance are you aware of?", "Describe a time you had to work in a team on a project with tight deadlines. How did you ensure accuracy and efficiency?"]', '2026-07-21 14:43:52', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (86, 247, 1, 72.0, '["BSc (Hons) in Surveying from PolyU \u2013 a top HK surveying school, automatically eligible for HKIS graduate pathway.", "Relevant internship at Rider Levett Bucknall (RLB) \u2013 a major QS consultancy in HK, providing hands-on experience in cost estimation and tender documentation.", "Strong software skills: AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, SPSS, Python, Power BI \u2013 highly relevant for field data and calibration.", "Possesses Construction Industry Safety Card (Green Card) \u2013 mandatory for site visits.", "Trilingual: Cantonese, English, Mandarin \u2013 meets language requirements for HK site communication."]', '["Limited work experience: only 3-month internship, no full-time or longer-term exposure.", "No explicit mention of self-motivation or ability to work under pressure \u2013 though this is subjective.", "No driving license \u2013 not required but could be a plus for field roles.", "Degree is QS-focused, but job title ''Junior Surveyor \u2013 Field Data & Calibration'' may imply land surveying or mapping; CV lacks land surveying equipment or mapping software (e.g., GIS, total station, GPS)."]', '["Emphasize any land surveying or mapping coursework or projects from your PolyU degree, if applicable, to align with ''Surveying and Mapping Engineering''.", "Add a bullet point in experience about ''field data collection'' or ''site measurement'' during RLB internship.", "Mention self-motivation and ability to work under pressure in the professional summary.", "If you have any experience with GIS, total station, or GPS, list it explicitly.", "Consider obtaining a HK driving license (Class 1/2) to enhance field role suitability."]', 'Recent BSc (Hons) Surveying graduate from The Hong Kong Polytechnic University with a summer internship at Rider Levett Bucknall (RLB) assisting senior QS team in measurement, cost estimation, and tender documentation. Proficient in AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, SPSS, Python, and Power BI. Possess Construction Industry Safety Card (Green Card) and trilingual in Cantonese, English, and Mandarin. HKIS Student Member with automatic eligibility for HKIS graduate pathway. Self-motivated and able to work under pressure, seeking a Junior Surveyor role to apply technical skills in field data and calibration.', 'Dear Hiring Manager,

I am writing to express my sincere interest in the Junior Surveyor – Field Data & Calibration position at Leadingnation. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, graduating in 2026, I am eager to contribute to your team while building a strong foundation in Hong Kong’s surveying profession.

