INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (89, 291, 1, 55.0, '["Fluent in Cantonese, English, and Mandarin - meets language requirement.", "Holds Construction Industry Safety Card (Green Card) - useful for site work.", "Has relevant software skills including AutoCAD and Revit, though not geospatial-specific.", "HKIS and RICS Student Member, showing professional awareness.", "Degree from PolyU, a well-regarded HK surveying institution."]', '["Degree is in Quantity Surveying, not Land Surveying or Geomatics - fundamental mismatch for this role.", "No experience or coursework in geospatial AI, spatial data, or related technologies.", "No GIS software skills (e.g., ArcGIS, QGIS) which are essential for geospatial roles.", "No HK driving license, which may be required for field work."]', '["Consider applying for QS roles instead, as your degree and experience align with that discipline.", "If interested in geospatial, pursue additional training or a master''s in Geomatics/GIS.", "Add any GIS or spatial analysis coursework or projects to your CV if applicable.", "Obtain a HK driving license if field work is anticipated.", "Tailor your CV to highlight any data analysis or AI-related skills (e.g., Python, Power BI) in a geospatial context."]', 'Geospatial AI Assistant Surveyor candidate with a BSc (Hons) in Surveying from The Hong Kong Polytechnic University (expected 2026). Fluent in Cantonese, English, and Mandarin. Holds Construction Industry Safety Card (Green Card) and is a HKIS and RICS Student Member. Proficient in AutoCAD, Revit, Navisworks, Bluebeam, and MS Project. Experienced in measurement, cost estimation, and BIM coordination through a summer internship at Rider Levett Bucknall (RLB) and a student assistant role at PolyU. Skilled in data analysis with Excel, VBA, SPSS, Python, and Power BI. Seeking to apply analytical and technical skills to support geospatial AI prototype development.', 'Dear Hiring Manager,

I am writing to express my keen interest in the Geospatial AI Assistant Surveyor position at Leadingnation, as advertised. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your firm’s pioneering work in integrating spatial data with cutting-edge technology.

My academic background and practical experience have equipped me with a solid foundation in both traditional surveying practices and modern digital tools. During my summer internship at Rider Levett Bucknall (RLB) in 2025, I assisted the senior quantity surveying team with measurement, cost estimation, and tender documentation, gaining firsthand exposure to Hong Kong’s construction workflows. Additionally, my role as a part-time student assistant at PolyU’s Building & Real Estate Department involved supporting research and teaching, which strengthened my analytical and collaborative skills. I am proficient in AutoCAD, Revit, Navisworks, CostX, and Power BI, and I have completed a CIC-accredited BIM Basic Modelling Course, ensuring I can contribute to geospatial data validation and prototype development.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. This pathway reflects my commitment to professional development and my understanding of the HK surveying profession, including familiarity with relevant Hong Kong ordinances and HKIS practice standards. I hold a valid Construction Industry Safety Card (Green Card) and am fluent in Cantonese, English, and Mandarin, enabling seamless communication with diverse stakeholders.

Leadingnation’s reputation for advancing geospatial AI in Hong Kong’s construction sector is inspiring, and I am excited by the prospect of supporting your team in developing and validating innovative prototypes. I am prepared to obtain any additional certifications required and am eager to bring my technical skills, bilingual fluency, and dedication to this role.

Thank you for considering my application. I look forward to the opportunity to discuss how I can contribute to Leadingnation’s success.

Yours sincerely,

[Your Name]', '["How familiar are you with the HKIS APC pathway for the Land Surveying division, and have you considered switching from QS to LS?", "What experience do you have with geospatial data formats (e.g., point clouds, LiDAR) or GIS software like ArcGIS?", "How would you approach validating a geospatial AI prototype for a HK infrastructure project, such as the Northern Metropolis?", "What HK regulations govern the use of spatial data and surveying practices (e.g., Land Survey Ordinance)?", "Describe a time you worked with a team to solve a technical problem; how did you contribute in a HK site environment?"]', '2026-07-21 14:44:08', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (90, 286, 1, 30.0, '["Has Cantonese proficiency, meeting language requirement.", "Holds Green Card, mandatory for site work.", "PolyU surveying degree shows relevant academic background, though in QS not LS.", "Proficient in AutoCAD and Revit, which may be useful for some land surveying tasks.", "HKIS Student Member demonstrates awareness of professional pathway."]', '["Degree discipline mismatch: BSc Surveying (QS) vs. Land Surveying required. Not eligible for HKIS Land Surveying Division membership.", "No land surveying experience: Internship and student assistant roles are QS-focused.", "No HK driving license, which may be needed for field work.", "No GIS or land surveying software skills (e.g., MicroStation, Leica Geo Office)."]', '["Do not apply for this role as the degree discipline mismatch is a fundamental gap. Consider QS roles instead.", "If interested in land surveying, consider a conversion master''s or relevant training.", "Obtain HK driving license if pursuing field-based surveying roles.", "Gain land surveying internship experience to build relevant skills.", "Join HKIS Land Surveying Division as a student member if eligible."]', 'Final-year BSc (Hons) Surveying student at The Hong Kong Polytechnic University, with a strong academic foundation in quantity surveying. Completed a summer internship at Rider Levett Bucknall (RLB) assisting senior QS team with measurement, cost estimation, and tender documentation. Also served as a part-time student assistant at PolyU''s Building & Real Estate Department, supporting research and teaching. Proficient in AutoCAD, Revit, CostX, Navisworks, and Bluebeam. Holds Construction Industry Safety Card (Green Card) and Revit Architecture Certified Professional. Fluent in Cantonese, English, and Mandarin. HKIS and RICS Student Member. Seeking to apply analytical and technical skills in a land surveying role, though currently lacking direct land surveying experience.', 'Dear Hiring Manager,

I am writing to express my strong interest in the Contract Assistant Land Surveyor position at the Home Affairs Department. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your department’s land surveying operations while further developing my professional competencies in a public-sector environment.

As a PolyU Surveying graduate, I am eligible for the HKIS graduate pathway via the Assessment of Professional Competence (APC) in the Land Surveying Division. I am currently an HKIS Student Member and an RICS Student Member, which reflects my commitment to meeting the profession’s highest standards. I understand that this role requires familiarity with land boundary surveys, topographic mapping, and geodetic work, and I have gained foundational exposure to these areas through my academic training at PolyU, including coursework in land surveying principles, GIS, and digital photogrammetry.

During my summer internship at Rider Levett Bucknall (RLB) in 2025, I assisted senior quantity surveyors with measurement, cost estimation, and tender documentation. While this experience was primarily in the quantity surveying stream, it honed my attention to detail, proficiency in AutoCAD, Revit, and CostX, and ability to work within strict deadlines—skills directly transferable to land surveying tasks such as preparing accurate plans and supervising survey teams. Additionally, my part-time role as a student assistant at PolyU’s Building and Real Estate Department involved supporting research on BIM coordination and data analysis using Python and Power BI, which aligns with the GIS and digital photogrammetry aspects of this role.

I note that the position requires candidates to have completed at least two years of relevant professional training and experience by September 2026. While I am currently completing my degree and have approximately six months of internship experience, I am actively seeking opportunities to fulfil this requirement. I hold a valid Construction Industry Safety Card (Green Card) and am prepared to obtain any additional certifications needed to meet the role’s requirements. I am also fluent in Cantonese, English, and Mandarin, which will facilitate effective communication with diverse stakeholders and field teams.

I am drawn to the Home Affairs Department’s reputation for delivering precise and reliable land surveying services that underpin Hong Kong’s infrastructure and land administration. I am confident that my technical skills, academic foundation, and proactive attitude will enable me to contribute meaningfully to your team.

Thank you for considering my application. I look forward to the opportunity to discuss how my background aligns with the needs of your department.

Yours faithfully,

