INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (111, 287, 1, 88.0, '["Degree in Surveying from PolyU (QS discipline) \u2013 directly matches job requirement.", "Summer internship at RLB (leading QS consultancy) \u2013 relevant experience in pre- and post-contract duties.", "Possesses Green Card \u2013 mandatory for site visits, already obtained.", "Fluent in Cantonese, English, and Mandarin \u2013 meets language requirements for HK market.", "Strong software skills including CostX, Revit, AutoCAD, and BIM \u2013 highly valued in modern QS roles."]', '["Limited work experience \u2013 only 0.5 years (internship) \u2013 may need to demonstrate ability to handle full responsibilities.", "No HK driving license \u2013 not required but could be an advantage for site visits.", "No explicit mention of knowledge of HK Standard Method of Measurement (SMM) or HKIS APC requirements \u2013 could be probed in interview."]', '["Highlight HKIS APC pathway awareness in CV \u2013 mention ''HKIS APC candidate'' or ''pursuing MHKIS''.", "Add a section on ''Relevant Coursework'' listing modules like Measurement, Contract Administration, Construction Law.", "Quantify internship achievements \u2013 e.g., ''Assisted in cost estimation for a HK$XX million residential project''.", "Obtain HK driving license (Class 1) if possible \u2013 useful for site visits.", "Include a brief statement on familiarity with HK construction regulations (e.g., Building Ordinance, SMM)."]', 'Final-year BSc (Hons) Surveying student at The Hong Kong Polytechnic University, with a summer internship at Rider Levett Bucknall (RLB) assisting senior quantity surveyors in pre- and post-contract duties. Proficient in measurement, cost estimation, tender documentation, and contract administration. Skilled in AutoCAD, Revit, CostX, Navisworks, Bluebeam, and MS Project. Bilingual in Cantonese, English, and Mandarin. Holder of Green Card and Revit Architecture Certified Professional. HKIS Student Member, eligible for HKIS graduate pathway. Seeking a graduate Quantity Surveyor role at Arcadis to apply technical knowledge and contribute to sustainable projects.', 'Dear Hiring Manager,

I am writing to express my strong interest in the Quantity Surveyor position at Arcadis, as advertised. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to a firm renowned globally for delivering sustainable design and consultancy solutions, and I am particularly drawn to Arcadis’s reputation for leading complex infrastructure and building projects across Hong Kong.

My academic training at PolyU, combined with practical experience as a summer intern at Rider Levitt Bucknall (RLB), has equipped me with a solid foundation in pre- and post-contract quantity surveying duties. During my internship, I assisted senior surveyors with measurement and take-off, cost estimation, and tender documentation using tools such as CostX, AutoCAD, and Revit. I also supported contract administration tasks, including valuation of progress payments and variation assessment, which align closely with the responsibilities outlined in your job description. Additionally, my proficiency in BIM coordination (Navisworks, Bluebeam) and data analysis (Excel, VBA, Power BI) enables me to contribute to efficient project delivery and cost control.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. I am familiar with the HKIS professional practice guidelines, relevant Hong Kong ordinances (e.g., the Building Ordinance and the Standard Form of Building Contract), and local construction practices. I hold a valid Construction Industry Safety Card (Green Card) and am prepared to commence immediately.

I am fluent in Cantonese, English, and Mandarin, and I possess strong communication skills in both written and spoken English and Chinese, as required. I am a proactive team player who thrives in collaborative environments and is eager to learn from Arcadis’s experienced professionals.

I welcome the opportunity to discuss how my skills and enthusiasm align with Arcadis’s vision. Thank you for considering my application. I look forward to your response.

Yours faithfully,

[Your Full Name]', '["How familiar are you with the HKIS APC requirements for the QS division, and what steps have you taken to prepare for it?", "Can you describe your experience with cost estimation using CostX? How would you handle a discrepancy between your estimate and a contractor''s quote?", "Arcadis is involved in large infrastructure projects in HK like the Kai Tak Development. How would you approach cost control for a project of that scale?", "What do you know about the HK Standard Method of Measurement (SMM) and its application in tender documentation?", "Describe a time during your internship at RLB when you had to work under pressure to meet a deadline. How did you manage it?"]', '2026-07-21 14:45:41', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (112, 288, 1, 68.0, '["Relevant degree: BSc (Hons) in Surveying from PolyU, a top HK surveying school.", "Strong software skills: AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, Power BI.", "Bilingual in Cantonese and English, plus Mandarin \u2013 ideal for HK-Macau role.", "Holds Green Card (Construction Industry Safety Card) \u2013 ready for site visits.", "HKIS Student Member and RICS Student Member, showing commitment to professional pathway."]', '["Only 0.5 years of internship experience, far short of the required 2 years with developer exposure.", "No developer experience \u2013 all experience is from cost consultancy (RLB) and academia.", "No HK driving license \u2013 may be needed for travel between HK and Macau sites.", "Limited evidence of full contract administration lifecycle experience (award to closeout)."]', '["Gain at least 1-2 more years of QS experience, ideally with a developer in HK or Macau.", "Highlight any coursework or projects related to developer-side procurement or contract administration.", "Obtain HK driving license (Class 1) to increase mobility for cross-border work.", "Emphasize any experience with contract management systems or data tracking in the CV.", "Consider enrolling in HKIS APC to show commitment to professional qualification."]', 'Recent BSc (Hons) Surveying graduate from The Hong Kong Polytechnic University with internship experience at Rider Levett Bucknall (RLB) assisting senior QS team in cost estimation, tender documentation, and contract administration. Proficient in AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, and Power BI. Bilingual in Cantonese and English with Mandarin proficiency. Holds Green Card and is a HKIS/RICS Student Member. Seeking a Quantity Surveyor role to apply analytical and software skills in developer-focused contract administration and procurement.', 'Dear Hiring Manager,

I am writing to express my interest in the Quantity Surveyor position within the Development Contracts Administration Team at Sands China. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your organisation’s world-class development projects across Macau and globally.

My academic background and practical experience have provided me with a solid foundation in quantity surveying practices relevant to the Hong Kong and Macau construction industries. As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. This pathway reflects my commitment to professional development and adherence to the high standards expected in our profession. I am also familiar with key HK ordinances and surveying practices, including the administration of contracts under standard forms commonly used in the region.

During my summer internship at Rider Levett Bucknall (RLB) in 2025, I supported a senior QS team with measurement and take-off, cost estimation, and tender documentation. I also assisted with contract administration tasks, including maintaining project registers and coordinating with stakeholders. This experience honed my proficiency in tools such as AutoCAD, Revit, CostX, and MS Project, as well as my ability to manage data and reports efficiently. Additionally, my part-time role as a student assistant at PolyU’s Building & Real Estate Department strengthened my research and analytical skills, particularly in using Excel, VBA, and Power BI for data processing.

I understand that the role involves supporting the bidding process, maintaining contract filing systems, and tracking project reports. My hands-on experience with BIM coordination, contract documentation, and supplier onboarding aligns well with these responsibilities. I also hold a valid Construction Industry Safety Card (Green Card) and am prepared to commence immediately.

I am drawn to Sands China’s reputation for delivering iconic integrated resort developments, and I am confident that my technical skills, trilingual abilities (Cantonese, English, Mandarin), and proactive attitude will enable me to contribute effectively to your team.

Thank you for considering my application. I look forward to the opportunity to discuss how I can support your development projects.

Yours sincerely,

[Your Name]', '["How familiar are you with the HKIS APC requirements for the QS division, and what steps have you taken to prepare for it?", "Can you describe your experience with cost estimation and the use of NRM or HK SMM in a developer context?", "Sands China has large-scale integrated resort projects in Macau. How would you approach contract administration for a project involving multiple cross-border stakeholders?", "What is your understanding of the procurement process under the HK Housing Authority or Development Bureau guidelines?", "Describe a time when you had to manage multiple priorities under tight deadlines. How did you ensure accuracy in your contract documentation?"]', '2026-07-21 14:45:42', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (113, 273, 1, 82.0, '["BSc (Hons) in Surveying from PolyU \u2014 directly relevant to QS role and qualifies for HKIS APC pathway.", "Summer internship at Rider Levett Bucknall (RLB) \u2014 a top QS consultancy in HK, providing practical QS experience.", "Possesses Green Card (Construction Industry Safety Card) \u2014 mandatory for site visits.", "Fluent in Cantonese, English, and Mandarin \u2014 meets language requirements for HK and Macau.", "Strong software skills including AutoCAD, Revit, CostX, and BIM \u2014 exceeds basic AutoCAD requirement."]', '["No indication of immediate availability \u2014 candidate is still studying (graduating 2026).", "No mention of willingness or ability to work in Macau \u2014 job requires working in Macau.", "Limited work experience (only 0.5 years) \u2014 less experienced candidates may be considered for trainee role, but still a gap.", "No HK driving license \u2014 not explicitly required but could be beneficial for site work."]', '["State availability: If you can start before graduation (e.g., part-time) or after June 2026, clarify in CV.", "Express willingness to work in Macau: Add a line like ''Willing to work in Macau'' or ''Open to relocation''.", "Highlight project types: Specify any residential, commercial, or government projects from RLB internship.", "Add HK driving license if you have one: Even if not required, it''s a plus for site roles.", "Emphasize immediate availability: If you can start soon, state ''Immediately available'' at the top."]', 'Detail-oriented Quantity Surveying graduate from The Hong Kong Polytechnic University (BSc Hons Surveying, 2026) with hands-on internship experience at Rider Levett Bucknall (RLB) in Hong Kong. Proficient in cost estimation, tender documentation, contract administration, and BIM coordination. Skilled in AutoCAD, Revit, CostX, Navisworks, and MS Project. Fluent in Cantonese, English, and Mandarin. Holder of Green Card and HKIS/RICS Student Memberships. Seeking a challenging role as Quantity Surveyor Trainee or Assistant Quantity Surveyor, with willingness to work in Macau. Immediate availability upon graduation.', 'Dear Hiring Manager,

I am writing to express my sincere interest in the Quantity Surveyor / Assistant Quantity Surveyor or Quantity Surveyor Trainee position at Wai Hung Hong. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your team and bring my technical skills and local industry knowledge to your Macau-based projects.

My academic background at PolyU, combined with my summer internship at Rider Levett Bucknall (RLB) in 2025, has provided me with practical exposure to cost estimation, tender documentation, and contract administration. I am proficient in AutoCAD, Revit, CostX, and MS Project, and I hold a Construction Industry Safety Card (Green Card), which I understand is essential for site visits. I am also a HKIS Student Member and, as a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, which I intend to pursue to further my professional development in Hong Kong’s surveying profession.

I understand that this role requires work in Macau, and I am fully prepared to relocate and adapt to the local regulatory environment. My trilingual fluency in Cantonese, English, and Mandarin will enable effective communication with clients, contractors, and colleagues across both Hong Kong and Macau. I am also familiar with the HKIS’s code of conduct and relevant Hong Kong ordinances, such as the Building Ordinance and the Standards of Measurement, which I have studied in depth during my degree.

Although my professional experience is currently at an entry level, I am hardworking, detail-oriented, and eager to learn. I am available to commence immediately and am committed to contributing to Wai Hung Hong’s reputation for quality and reliability in the region.

Thank you for considering my application. I look forward to the opportunity to discuss how my skills and enthusiasm align with your team’s needs.

Yours faithfully,

[Your Full Name]', '["How familiar are you with the HKIS APC requirements for the QS division, and what steps have you taken to prepare for it?", "Can you describe your experience with cost estimation and the use of NRM or HK SMM during your internship at RLB?", "Given that this role requires working in Macau, how would you adapt to the different construction regulations and market practices there?", "What is your understanding of the Hong Kong Standard Method of Measurement (SMM) and how it differs from other standards?", "Describe a time during your internship when you had to work under pressure to meet a deadline. How did you handle it?"]', '2026-07-21 14:45:44', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (114, 276, 1, 45.0, '["Candidate has a degree from PolyU, a well-regarded HK surveying school, and is an HKIS Student Member.", "Candidate has Cantonese, English, and Mandarin language skills, meeting the language requirements.", "Candidate holds a Green Card, which is beneficial for site work.", "Candidate has some software skills including AutoCAD and Revit, though not GIS.", "Candidate has internship experience in the HK construction industry (RLB), showing some industry exposure."]', '["Degree is in general Surveying (QS stream), not Land Surveying. The job requires a degree specifically in Land Surveying or Geomatics for HKIS LS division recognition.", "No GIS software skills (e.g., ArcGIS, QGIS) which are essential for land surveying and geospatial roles.", "No land surveying internship or work experience; all experience is QS-related.", "No HK driving license, which may be required for field work."]', '["If you have taken any land surveying modules or GIS courses at PolyU, list them explicitly to show relevance.", "Consider obtaining GIS certifications (e.g., Esri ArcGIS) to strengthen your profile for land surveying roles.", "Gain land surveying experience through internships or projects, even if academic, to demonstrate interest.", "If you have a driving license, add it to your CV; if not, consider obtaining one for field roles.", "Tailor your CV to highlight any spatial data or geospatial analysis experience, even from other disciplines."]', 'Recent BSc (Hons) Surveying graduate from The Hong Kong Polytechnic University with a strong foundation in surveying principles and a keen interest in land surveying and geospatial technology. Possess a Green Card and HKIS Student Membership. Proficient in AutoCAD, Revit, and BIM coordination, with basic knowledge of measurement and cost estimation. Fluent in Cantonese, English, and Mandarin. Completed a summer internship at Rider Levett Bucknall (RLB) assisting senior QS team, and a part-time student assistant role at PolyU supporting research. Eager to apply analytical skills and learn geospatial AI technologies. Seeking an Assistant Land Surveyor position to contribute to innovative spatial data projects and develop expertise in land surveying under HKIS APC training.', 'Dear Hiring Manager,

I am writing to express my strong interest in the Assistant Land Surveyor position at Esri China (Hong Kong) Ltd, as advertised. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your team’s pioneering work in geospatial AI and smart city development.

My academic background and practical experience align well with the requirements of this role. Through my internship at Rider Levett Bucknall (RLB) and my part-time role as a student assistant at PolyU’s Building & Real Estate Department, I have developed a solid foundation in measurement, cost estimation, and BIM coordination using tools such as AutoCAD, Revit, Navisworks, and CostX. I am also proficient in data analysis with Excel, VBA, and Power BI, which I understand is increasingly relevant to geospatial data processing and AI-driven projects.

As a PolyU Surveying graduate, I am eligible for the HKIS graduate pathway via the Assessment of Professional Competence (APC) in the Land Surveying Division. I am also a current HKIS Student Member and hold the Construction Industry Safety Card (Green Card), so I am fully prepared to commence work immediately without any certification gaps.

I am particularly drawn to Esri’s reputation as a leader in geospatial technology in Hong Kong and its role in advancing the Government’s smart city initiatives. I understand the importance of the HKIS’s professional standards and am familiar with relevant Hong Kong ordinances and surveying practices. My trilingual proficiency in Cantonese, English, and Mandarin will enable effective collaboration with diverse stakeholders, including government clients, tech ventures, and academic partners.

I am excited by the prospect of contributing to the development and validation of geospatial AI sandbox prototypes, and I am confident that my technical skills, combined with my eagerness to learn, will allow me to add value to your team. I look forward to the opportunity to discuss how my background can support Esri’s innovative projects.

Thank you for considering my application.

Yours sincerely,

[Your Name]', '["What do you know about the HKIS APC pathway for the Land Surveying Division, and how do you plan to meet the training requirements?", "How would you use geospatial AI to improve land surveying accuracy in a Hong Kong context?", "What experience do you have with GIS software like ArcGIS or QGIS, and how would you apply it to spatial data projects?", "Can you explain the role of the Land Survey Ordinance in Hong Kong and its impact on land boundary surveys?", "Describe a time when you had to work with a team on a project with tight deadlines. How did you handle it?"]', '2026-07-21 14:45:47', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (115, 262, 1, 82.0, '["Relevant degree: BSc (Hons) in Surveying from PolyU, a top HK surveying school, directly aligned with QS discipline.", "Strong software skills: Proficient in CostX, AutoCAD, Revit, Navisworks, Bluebeam, and data analysis tools (Python, Power BI).", "HKIS and RICS student memberships, indicating commitment to professional pathway.", "Cantonese proficiency, essential for HK site-based roles.", "Green Card holder, meeting mandatory site safety requirement."]', '["Limited work experience: Only 3 months of internship (RLB) and part-time student assistant role; no full-time or post-graduate experience.", "No HK driving license, which may be required for site visits to remote infrastructure projects.", "No explicit mention of infrastructure project experience; Turner & Townsend role is for infrastructure, but CV lacks specific infrastructure exposure.", "Graduating in 2026, so not yet available for full-time employment; may need to clarify availability."]', '["Highlight any infrastructure-related coursework or projects from PolyU (e.g., highway, railway, or utility projects) in the CV.", "Obtain HK driving license (Class 1) before applying, as it is often required for infrastructure site roles.", "Quantify internship achievements at RLB (e.g., ''Assisted in cost estimation for a HK$XX million residential project'' or ''Prepared tender documentation for 3 projects'').", "Add a section on ''Relevant Coursework'' to demonstrate knowledge of infrastructure cost management (e.g., civil engineering measurement, NEC contracts).", "State availability for full-time employment after graduation (2026) and willingness to start as an APC candidate."]', 'Final-year BSc (Hons) Surveying student at The Hong Kong Polytechnic University, with a strong foundation in quantity surveying and cost management. Completed a summer internship at Rider Levett Bucknall (RLB) where I assisted senior QS team in measurement, cost estimation, and tender documentation for HK construction projects. Proficient in CostX, AutoCAD, Revit, Navisworks, and Bluebeam, with additional skills in data analysis using Python and Power BI. Holder of Green Card and student memberships in HKIS and RICS, demonstrating commitment to professional development. Fluent in Cantonese, English, and Mandarin. Seeking a Cost Consultant role in infrastructure to apply my technical skills and contribute to Turner & Townsend''s project delivery.', 'Dear Hiring Manager,

I am writing to express my sincere interest in the Cost Consultant, Infrastructure position at Turner & Townsend, as advertised. As a final-year BSc (Hons) Surveying student at The Hong Kong Polytechnic University, I have long admired Turner & Townsend’s reputation for delivering world-class infrastructure and real estate projects across Hong Kong and the Asia-Pacific region. Your firm’s commitment to transforming complexity into success, particularly on high-profile infrastructure programmes, aligns closely with my career aspirations in cost consultancy.

My academic foundation at PolyU, combined with hands-on experience as a summer intern at Rider Levitt Bucknall (RLB), has equipped me with a solid grounding in pre- and post-contract cost management. During my internship, I assisted the senior QS team with measurement and take-off, cost estimation, and tender documentation for Hong Kong-based projects. I am proficient in industry-standard tools including CostX, AutoCAD, Revit, Navisworks, and MS Project, and I have developed strong analytical skills through my work with Excel, VBA, Power BI, and Python. Additionally, my CIC-accredited BIM Basic Modelling Course and Autodesk Revit certification enable me to contribute effectively to BIM-coordinated project environments.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. I have a working understanding of the HKIS professional assessment framework and relevant Hong Kong ordinances, including the Building Ordinance and standard forms of contract commonly used in the local industry. I am fluent in Cantonese, English, and Mandarin, which allows me to communicate seamlessly with diverse project stakeholders.

I hold a valid Construction Industry Safety Card (Green Card) and am fully prepared to commence work immediately upon graduation in 2026. I am eager to bring my technical skills, local knowledge, and collaborative mindset to Turner & Townsend’s infrastructure team.

Thank you for considering my application. I look forward to the opportunity to discuss how I can contribute to your continued success in Hong Kong.

Yours sincerely,

[Your Name]', '["How familiar are you with the HKIS APC requirements for the QS division, and what steps have you taken to prepare for the APC process?", "Can you describe your experience with cost estimation and rate analysis? How would you approach developing a cost plan for a large-scale infrastructure project in Hong Kong?", "Turner & Townsend has been involved in major HK infrastructure projects like the Hong Kong-Zhuhai-Macao Bridge and the West Kowloon Cultural District. What do you know about these projects, and how would you apply cost management principles to similar projects?", "What is your understanding of the Hong Kong Standard Method of Measurement (SMM) and its application in infrastructure projects?", "Describe a time during your internship at RLB when you had to resolve a discrepancy in measurement or cost data. How did you handle it, and what was the outcome?"]', '2026-07-21 14:45:59', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (116, 263, 1, 55.0, '["Degree from PolyU in Surveying (QS) - directly relevant and HKIS eligible.", "Strong software skills: AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, Excel, VBA, SPSS, Python, Power BI.", "Has Green Card (Construction Industry Safety Card) - mandatory for site work.", "Fluent in Cantonese, English, and Mandarin - essential for HK client and contractor communication.", "HKIS and RICS Student Member - shows commitment to professional pathway."]', '["No MRICS or equivalent professional membership - job requires MRICS/RICS membership, candidate is only a student member.", "Insufficient experience: only 0.5 years internship, job requires proven expertise in cost forecasting, earned value analysis, etc.", "No evidence of stakeholder relationship building or commercial challenge resolution.", "No HK driving license - may be required for site visits."]', '["Gain at least 2-3 years of post-graduation QS experience before applying for AD-level roles.", "Work towards achieving MRICS or HKIS professional membership.", "Highlight any specific HK infrastructure project experience if available.", "Obtain HK driving license if planning to work on site-based roles.", "Emphasize any cost planning or risk management coursework or projects in CV."]', 'Recent BSc (Hons) Surveying graduate from The Hong Kong Polytechnic University with a strong foundation in quantity surveying and cost management. Completed a summer internship at Rider Levett Bucknall (RLB) assisting senior QS team with measurement, cost estimation, and tender documentation. Proficient in digital tools including AutoCAD, Revit, CostX, Navisworks, Bluebeam, MS Project, and Power BI. Holds Construction Industry Safety Card (Green Card) and is a student member of HKIS and RICS. Fluent in Cantonese, English, and Mandarin. Seeking a challenging role in cost consultancy to apply analytical skills and contribute to large-scale infrastructure projects in Hong Kong.', 'Dear Hiring Manager,

I am writing to express my strong interest in the Cost Consultant position at Mace, as advertised. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to Mace’s distinguished portfolio, particularly your large-scale public infrastructure enhancement programme involving complex civil, structural, and MEP works across Hong Kong’s heavily used transport corridors. I have long admired Mace’s reputation for delivering value-driven outcomes and ambitious projects, and I am confident that my technical foundation and local training align well with this role.

My academic background at PolyU, combined with my summer internship at Rider Levett Bucknall (RLB) from June to August 2025, has provided me with hands-on experience in measurement, cost estimation, tender documentation, and contract administration. At RLB, I supported the senior QS team on live projects, strengthening my proficiency in AutoCAD, Revit, CostX, Navisworks, and Bluebeam. Additionally, my part-time role as a student assistant at PolyU’s Building & Real Estate Department has honed my analytical skills using Excel, VBA, Power BI, and Python for data-driven cost planning and reporting.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. I am familiar with HKIS standards, relevant Hong Kong ordinances, and local surveying practices, including the application of BIM coordination under CIC-accredited frameworks. I hold a Construction Industry Safety Card (Green Card) and am prepared to commence immediately, ensuring full compliance with site safety requirements.

I am particularly drawn to Mace’s focus on continuous improvement and best practice application. My experience with Revit Architecture Certified Professional and BIM Basic Modelling (CIC-accredited) positions me to support procurement strategies, cost control, and stakeholder relationships on complex infrastructure projects. I am eager to bring my technical skills, trilingual fluency in Cantonese, English, and Mandarin, and a proactive learning attitude to your team.

Thank you for considering my application. I look forward to the opportunity to discuss how I can contribute to Mace’s success.

Yours sincerely,

[Your Full Name]', '["What do you understand about the HKIS APC requirements for the QS division, and how do you plan to complete your APC?", "How familiar are you with the Hong Kong Standard Method of Measurement (SMM) and its application in cost planning?", "Mace is involved in large-scale public infrastructure projects in Hong Kong. How would you approach cost forecasting for a complex multi-site transport corridor upgrade?", "What are the key considerations under the Hong Kong Building Ordinance when preparing cost estimates for a public infrastructure project?", "Describe a time when you had to resolve a discrepancy in measurement or cost data during your internship. How did you handle it?"]', '2026-07-21 14:46:00', NULL, NULL);
INSERT OR REPLACE INTO cv_match_results (id, job_id, cv_id, match_score, strengths, gaps, suggestions, tailored_cv, cover_letter, interview_questions, created_at, hard_requirements_match, soft_requirements_match) VALUES (117, 250, 1, 72.0, '["PolyU BSc Surveying degree is recognized by HKIS and eligible for APC pathway.", "Possesses Green Card (Construction Industry Safety Card) \u2013 mandatory for site work.", "Trilingual in Cantonese, English, and Mandarin \u2013 meets language requirement.", "Strong software skills including AutoCAD, Revit, CostX, and BIM \u2013 relevant to building surveying tasks.", "HKIS and RICS student memberships demonstrate commitment to professional development."]', '["Degree is in Surveying (QS-focused) rather than Building Surveying \u2013 may lack BS-specific knowledge.", "Internship experience is in quantity surveying (RLB), not building surveying \u2013 no direct BS experience.", "No mention of facility management, maintenance, or leisure facility exposure \u2013 key for this role.", "No HK driving license \u2013 could be a minor gap for site visits."]', '["Highlight any coursework or projects related to building surveying, facility management, or building regulations.", "Obtain HK driving license (Class 1) to increase flexibility for site visits.", "Emphasize transferable skills from QS internship (e.g., cost control, contract admin) that apply to BS.", "Add a section on ''Interest in Facility Management'' to align with the job''s focus.", "List any building-related software proficiency (e.g., BIM for building condition surveys) explicitly."]', 'Detail-oriented BSc Surveying graduate from The Hong Kong Polytechnic University, with a strong foundation in building surveying principles and hands-on experience in cost estimation, tender documentation, and contract administration through a summer internship at Rider Levett Bucknall. Proficient in AutoCAD, Revit, CostX, and BIM, with a Construction Industry Safety Card (Green Card) and trilingual fluency in Cantonese, English, and Mandarin. HKIS and RICS student member, committed to pursuing the HKIS APC pathway. Eager to apply analytical and coordination skills to support facility management, maintenance, and alteration works at Chinese Recreation Club Hong Kong. Self-motivated team player with strong communication skills, ready to contribute to project planning, site supervision, and compliance tasks.', 'Dear Hiring Manager,

I am writing to express my keen interest in the Graduate Trainee – Building Surveying position at Chinese Recreation Club Hong Kong. As a final-year BSc (Hons) in Surveying student at The Hong Kong Polytechnic University, I am eager to contribute to your team while pursuing a structured pathway towards registration as a Registered Professional Surveyor.

My academic background and practical experience have equipped me with a solid foundation in building surveying principles. During my summer internship at Rider Levett Bucknall (RLB) in 2025, I assisted senior quantity surveyors with measurement and take-off, cost estimation, and tender documentation for Hong Kong-based projects. This experience honed my technical skills in AutoCAD, Revit, CostX, and Navisworks, and deepened my understanding of local construction practices. Additionally, my part-time role as a student assistant at PolyU’s Building and Real Estate Department involved supporting research and teaching, which strengthened my analytical abilities using Excel, VBA, and Power BI.

As a PolyU Surveying graduate, I am eligible for the HKIS APC graduate pathway, and I am already an HKIS Student Member. I am familiar with the HKIS assessment framework and relevant Hong Kong ordinances, including the Buildings Ordinance and its subsidiary regulations. I hold a valid Construction Industry Safety Card (Green Card) and a CIC-accredited BIM Basic Modelling certificate, ensuring I am ready to support site supervision and compliance matters from day one.

